// Script Continued Below
function onLoad() {
	//Type appropriate comment here, and begin script below

	//KT - RLS - STRY0065050; 03/30/2020

	//OU Member Administrator
	g_form.showFieldMsg("can_manage_ou_members", 
						getMessage("Tasker - Allows the user to add/update members for the selected Organizational Unit."),
						"info");

	//Global Hierarchy Administrator
	g_form.showFieldMsg("user_is_organization_admin", 
						getMessage("Tasker - Allows the user to add/update Sub Organizational Units in all OUs, and manage their Members."),
						"info");

	//OU Hierarchy Administrator
	g_form.showFieldMsg("is_office_administrator", 
						getMessage("Tasker - Allows the user to add/update Sub Organizational Units, and manage Members in the selected Organizational Unit."),
						"info");

	//Personal Template Designer
	g_form.showFieldMsg("has_personal_process_rights", 
						getMessage("Tasker - Allows the user to create/update/delete Personal templates."),
						"info");

	//OU Template Designer
	g_form.showFieldMsg("has_ou_process_rights",
						getMessage("Tasker - Allows the user to create/update/delete Personal & OU templates."),
						"info");

	//Global Template Designer
	g_form.showFieldMsg("can_manage_global_processes", 
						getMessage("Tasker - Allows the user to create/update/delete Personal, OU, and Global templates."),
						"info");

	//Template Designer Permissions Administrator
	g_form.showFieldMsg("can_manage_process_permissions", 
						getMessage("Tasker - Manage template permissions for Personal, OU, and Global template designers."),
						"info");

	//Tasking Authority / Task Manager
	g_form.showFieldMsg("office_task_authority", 
						getMessage("Tasker - Manage Task assignment for the selected Organizational Unit | Inherits OU Template Designer role."), 
						"info");

	//Global Tasking Authority / Task Administrator
	g_form.showFieldMsg("is_global_tasking_authority", 
						getMessage("Tasker - Manage Task assignment in all OUs | Provide Tasking Manager role for an OU | Reviews and approves Suggested Tasks | Inherits Global Template Designer role."), 
						"info");

	// STRY0112585 - Task Executive- Update for New Member Form
	g_form.showFieldMsg("is_task_executive", 
						getMessage("Tasker - Limit notifications to your tasks | Task assignment in all OUs | Create/Run/Edit Global Templates."), 
						"info");

}
